"use strict";const t=require("../../common/vendor.js"),o=require("../../services/cartService.js"),a=t.defineStore("cart",{state:()=>({list:[],totalCount:0,totalAmount:0,loading:!1}),actions:{async fetchCart(){this.loading=!0;try{const t=await o.getCart();this.list=t.list,this.totalCount=t.totalCount,this.totalAmount=t.totalAmount}finally{this.loading=!1}},async add(t){const a=await o.addCartItem(t);this.list=a.list,this.totalCount=a.totalCount,this.totalAmount=a.totalAmount},async changeQuantity(t,a){const s=Math.max(1,a),i=await o.updateCartItem(t,s);this.list=i.list,this.totalCount=i.totalCount,this.totalAmount=i.totalAmount},async remove(t){const a=await o.deleteCartItem(t);this.list=a.list,this.totalCount=a.totalCount,this.totalAmount=a.totalAmount}}});exports.useCartStore=a;
